 Method;template <typename T> struct alignas(8) DexCachePair;// C++ mirror of java.lang.Classclass EXPORT MANAGED Class final : public Object { public: MIRROR_CLASS("Ljava/lang/Class;"); // 'reference_instance_offsets_' may contain up to 31 reference offsets. If // more bits are required, then we set the most-significant bit and store the // number of 32-bit bitmap entries required in the remaining bits. All the // required bitmap entries after stored after static fields (at the end of the class). static constexpr uint32_t kVisitReferencesSlowpathShift = 31; static constexpr uint32_t kVisitReferencesSlowpathMask = 1u << kVisitReferencesSlowpathShift; // Shift primitive type by kPrimitiveTypeSizeShiftShift to get the component type size shift // Used for computing array size as follows: // array_bytes = header_size + (elements << (primitive_type >> kPrimitiveTypeSizeShiftShift)) static constexpr uint32_t kPrimitiveTypeSizeShiftShift = 16; static constexpr uint32_t kPrimitiveTypeMask = (1u << kPrimitiveTypeSizeShiftShift) - 1; template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags, bool kWithSynchronizationBarrier = true> ClassStatus GetStatus() REQUIRES_SHARED(Locks::mutator_lock_) { // Reading the field without barrier is used exclusively for IsVisiblyInitialized(). int32_t field_value = kWithSynchronizationBarrier ? GetField32Volatile<kVerifyFlags>(StatusOffset()) : GetField32<kVerifyFlags>(StatusOffset()); // Avoid including "subtype_check_bits_and_status.h" to get the field. // The ClassStatus is always in the 4 most-significant bits of status_. return enum_cast<ClassStatus>(static_cast<uint32_t>(field_value) >> (32 - 4)); } // This is static because 'this' may be moved by GC. static void SetStatus(Handle<Class> h_this, ClassStatus new_status, Thread* self) REQUIRES_SHARED(Locks::mutator_lock_) REQUIRES(!Roles::uninterruptible_); // Used for structural redefinition to directly set the class-status while // holding a strong mutator-lock. void SetStatusLocked(ClassStatus new_status) REQUIRES(Locks::mutator_lock_); void SetStatusForPrimitiveOrArray(ClassStatus new_status) REQUIRES_SHARED(Locks::mutator_lock_); static constexpr MemberOffset StatusOffset() { return MemberOffset(OFFSET_OF_OBJECT_MEMBER(Class, status_)); } // Returns true if the class has been retired. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsRetired() REQUIRES_SHARED(Locks::mutator_lock_) { return GetStatus<kVerifyFlags>() == ClassStatus::kRetired; } // Returns true if the class has failed to link. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsErroneousUnresolved() REQUIRES_SHARED(Locks::mutator_lock_) { return GetStatus<kVerifyFlags>() == ClassStatus::kErrorUnresolved; } // Returns true if the class has failed to initialize. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsErroneousResolved() REQUIRES_SHARED(Locks::mutator_lock_) { return GetStatus<kVerifyFlags>() == ClassStatus::kErrorResolved; } // Returns true if the class status indicets that the class has failed to link or initialize. static bool IsErroneous(ClassStatus status) { return status == ClassStatus::kErrorUnresolved || status == ClassStatus::kErrorResolved; } // Returns true if the class has failed to link or initialize. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsErroneous() REQUIRES_SHARED(Locks::mutator_lock_) { return IsErroneous(GetStatus<kVerifyFlags>()); } // Returns true if the class has been loaded. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsIdxLoaded() REQUIRES_SHARED(Locks::mutator_lock_) { return GetStatus<kVerifyFlags>() >= ClassStatus::kIdx; } // Returns true if the class has been loaded. template<VerifyObjectFlags kVerifyFlags = kDefaultVerifyFlags> bool IsLoaded() REQUIRES_SHARED(Locks::mutator_lock_) { return GetStatus<kVerifyFlags>() >= ClassStatus::kLoaded; } // Returns true if the class has been linked. template<VerifyObjectFlags kVerifyFlags = k